global.schema:
type ContributorProfileState {
    legalName: String
    displayName: String!
    kind: ContributorKind!
    websiteUrl: URL
    twitterHandle: String
    farcasterHandle: String
    walletAddresses: [ContributorWallet!]!
    governanceEndpoints: [GovernanceEndpoint!]!
    trustLevel: TrustLevel!
}

enum ContributorKind {
    DAO
    FOUNDATION
    COMPANY
    INDIVIDUAL
}

enum TrustLevel {
    VERIFIED
    ANNOUNCED
    ANONYMOUS
}

enum GovernancePlatform {
    SNAPSHOT
    TALLY
    FORUM
    AGORA
    OTHER
}

type ContributorWallet {
    id: OID!
    chainId: Int!
    address: EthereumAddress!
    label: String
}

type GovernanceEndpoint {
    id: OID!
    platform: GovernancePlatform!
    url: URL!
}

operations.reducer:
if (action.input.legalName) state.legalName = action.input.legalName;
if (action.input.displayName) state.displayName = action.input.displayName;
if (action.input.kind) state.kind = action.input.kind;
if (action.input.websiteUrl) state.websiteUrl = action.input.websiteUrl;
if (action.input.twitterHandle) state.twitterHandle = action.input.twitterHandle;
if (action.input.farcasterHandle) state.farcasterHandle = action.input.farcasterHandle;

operations.schema:
input AddWalletInput {
    id: OID!
    chainId: Int!
    address: EthereumAddress!
    label: String
}

operations.reducer:
const dup = state.walletAddresses.find(
  (w) => w.address.toLowerCase() === action.input.address.toLowerCase() && w.chainId === action.input.chainId,
);
if (dup) throw new DuplicateWalletError('Wallet already registered for this chain');
state.walletAddresses.push({
  id: action.input.id,
  chainId: action.input.chainId,
  address: action.input.address,
  label: action.input.label || null,
});

const idx = state.walletAddresses.findIndex((w) => w.id === action.input.id);
if (idx === -1) throw new WalletNotFoundError('No wallet with that id');
state.walletAddresses.splice(idx, 1);

operations.schema:
input AddGovernanceEndpointInput {
    id: OID!
    platform: GovernancePlatform!
    url: URL!
}

operations.reducer:
const dup = state.governanceEndpoints.find(
  (e) => e.platform === action.input.platform && e.url === action.input.url,
);
if (dup) throw new DuplicateGovernanceEndpointError('Governance endpoint already registered');
state.governanceEndpoints.push({
  id: action.input.id,
  platform: action.input.platform,
  url: action.input.url,
});

const idx = state.governanceEndpoints.findIndex((e) => e.id === action.input.id);
if (idx === -1) throw new GovernanceEndpointNotFoundError('No governance endpoint with that id');
state.governanceEndpoints.splice(idx, 1);
